package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Closeable;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVPrinterTest {

    private Appendable appendable;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        appendable = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(appendable, format);
    }

    @Test
    void close_whenOutIsCloseable_shouldCloseOut() throws IOException {
        Closeable closeable = mock(Closeable.class);

        // Use reflection to create CSVPrinter with Closeable 'out' since Closeable is not Appendable
        CSVPrinter printerWithCloseable = createCSVPrinterWithOut(closeable, format);

        printerWithCloseable.close();

        verify(closeable, times(1)).close();
    }

    @Test
    void close_whenOutIsNotCloseable_shouldNotThrow() {
        assertDoesNotThrow(() -> printer.close());
    }

    private static CSVPrinter createCSVPrinterWithOut(Object out, CSVFormat format) {
        try {
            // Use the public constructor with Appendable, but out is not Appendable.
            // So create a proxy Appendable that delegates to the Closeable for close.
            Appendable proxyAppendable = new Appendable() {
                @Override
                public Appendable append(CharSequence csq) {
                    return this;
                }

                @Override
                public Appendable append(CharSequence csq, int start, int end) {
                    return this;
                }

                @Override
                public Appendable append(char c) {
                    return this;
                }
            };

            // Use reflection to instantiate CSVPrinter with the proxy
            return new CSVPrinter(proxyAppendable, format) {
                // Override the 'out' field to the Closeable passed in
                {
                    java.lang.reflect.Field outField = CSVPrinter.class.getDeclaredField("out");
                    outField.setAccessible(true);
                    outField.set(this, out);
                }
            };
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
